import cv2
import numpy as np
import dlib
import os
from flask import Flask, request, jsonify

app = Flask(__name__)

# Load pre-trained face recognizer model
model = cv2.dnn.readNetFromTorch('face_recognition_model.pt')

# Load label encoder
label_encoder_path = 'labels_map.txt'
le = cv2.dnn_reader.DefaultLabelEncoder()
class_names = le.readLabelMap(label_encoder_path)

# Path to employee photos directory
employee_photos_dir = 'employee_photos/'

def create_face_embeddings():
    employee_ids = os.listdir(employee_photos_dir)
    employees = {}

    for employee_id in employee_ids:
        employee_photo_path = os.path.join(employee_photos_dir, employee_id, 'employee_{}.jpg'.format(employee_id))
        (img, _), rects = dlib.get_face_detector().run([cv2.imread(employee_photo_path)], 1)
        faces = [rect for idx, rect in enumerate(rects) if cv2.contoursArea(rect) > 1000]

        if len(faces) == 0:
            continue

        face = faces[0]
        (x, y, w, h) = (face.left(), face.top(), face.right() + 1, face.bottom() + 1)
        cropped_image = img[y:h, x:w]
        resized_img = cv2.resize(cropped_image, (96, 112))
        resized_img = np.expand_dims(resized_img, axis=0)
        resized_img = np.expand_dims(resized_img, axis=3)

        faces_input = np.zeros((1, 3, 96, 112))
        faces_input[0] = resized_img
        faces_input = faces_input.transpose((0, 2, 3, 1))

        predictions = model.forward(faces_input)
        face_embbeding = predictions[Predicted_face_embedding_layer_name]
        employees[int(employee_id)] = face_embbeding.flatten()
    return employees

def predict_face(frame):
    # Preprocessing for the given frame
    face_detector = dlib.get_frontal_face_detector()
    faces = face_detector(frame, 1)

    face_recognition_results = []

    for face in faces:
        (x, y, w, h) = face.left(), face.top(), face.right() + 1, face.bottom() + 1
        cropped_face = frame[y:h, x:w]
        resized_img = cv2.resize(cropped_face, (96, 112))
        resized_img = np.expand_dims(resized_img, axis=0)
        resized_img = np.expand_dims(resized_img, axis=3)

        faces_input = np.zeros((1, 3, 96, 112))
        faces_input[0] = resized_img
        faces_input = faces_input.transpose((0, 2, 3, 1))

        predictions = model.forward(faces_input)
        confidence = predictions[Predicted_confidence_layer_name][0].item()
        class_id = np.argmax(predictions[Predicted_probabilities_layer_name])
        class_probability = predictions[Predicted_probabilities_layer_name][class_id]

        face_recognition_results.append((class_id, confidence, class_probability))
    return face_recognition_results

# Load pre-trained employee faces
employees = create_face_embeddings()

@app.route('/predict', methods=['POST'])
def predict():
    if request.method == 'POST':
        data = request.files['image']
        face_recognition_results = predict_face(data)
        results = []
        for result in face_recognition_results:
            class_id, confidence, class_probability = result
            class_name = class_names[class_id][1]
            results.append({'class_id': class_id, 'class_name': class_name, 'confidence': confidence,
                             'probability': list(class_probability)})
        return jsonify(results)